#!/usr/bin/env node

import { spawn } from 'child_process'

const args = process.argv.slice(2)
const command = args[0]
const subcommand = args[1]

if (args.includes('--version')) {
    console.log('Maki v1.0.2')
    process.exit(0)
}

if (args.includes('--help')) {
    console.log(`Maki v1.0.2
Commands:
  maki new <game>     scaffold a new project
  maki dev            start dev server
  maki new sprite     scaffold and register a sprite
  maki tilemap        open visual map editor
  maki collision      open tilemap editor in collision mode
  maki build          build for production
  maki --version      show version
  maki --help         show this help
  maki --update       update to latest`)
    process.exit(0)
}

if (args.includes('--update')) {
    const child = spawn('npm', ['install', '-g', 'maki@latest'], { stdio: 'inherit' })
    child.on('close', code => process.exit(code))
} else if (command === 'build') {
    const { build } = await import('../src/build.js')
    await build()
} else if (command === 'dev') {
    const { dev } = await import('../src/dev.js')
    await dev()
} else if (command === 'new') {
    if (subcommand === 'sprite') {
        const { sprite } = await import('../src/sprite.js')
        sprite()
    } else {
        const { create } = await import('../src/create.js')
        create()
    }
} else if (command === 'tilemap') {
    const { tilemap } = await import('../src/tilemap.js')
    await tilemap()
} else if (command === 'collision') {
    const { tilemap } = await import('../src/tilemap.js')
    await tilemap({ collisionMode: true })
} else {
    console.log(`Unknown command: ${command}`)
    console.log('Available commands: dev, new <game-name>, new sprite, tilemap, collision')
}